pub async fn key_add(
    archive_dir: &Path,
    current_password: &str,
    new_secret: KeySlotSecret,
    label: Option<String>,
) -> Result<AddKeyResult, KeyError> {
    // 1. Load config.json
    let config_path = archive_dir.join("config.json");
    let mut config: Config = serde_json::from_str(&fs::read_to_string(&config_path)?)?;

    // 2. Derive KEK from current password and unwrap DEK
    let dek = unwrap_dek_from_any_slot(&config, current_password)?;

    // 3. Generate new key slot
    let new_slot = match new_secret {
        KeySlotSecret::Password(pw) => {
            create_password_slot(&pw, &dek, &config.export_id, config.key_slots.len() as u32)?
        }
        KeySlotSecret::Recovery => {
            let secret = generate_recovery_secret();
            let slot = create_recovery_slot(&secret, &dek, &config.export_id, config.key_slots.len() as u32)?;
            return Ok(AddKeyResult::RecoverySlot { slot, secret });
        }
    };

    // 4. Add slot to config
    config.key_slots.push(new_slot);

    // 5. Write updated config.json
    fs::write(&config_path, serde_json::to_string_pretty(&config)?)?;

    // 6. Update integrity.json if present
    update_integrity_hash(&archive_dir, "config.json")?;

    Ok(AddKeyResult::PasswordSlot { slot_id: config.key_slots.len() - 1 })
}

fn create_password_slot(
    password: &str,
    dek: &[u8; 32],
    export_id: &[u8; 16],
    slot_id: u32,
) -> Result<KeySlot, KeyError> {
    let mut salt = [0u8; 16];
    let mut nonce = [0u8; 12];
    rand::thread_rng().fill_bytes(&mut salt);
    rand::thread_rng().fill_bytes(&mut nonce);

    // Derive KEK via Argon2id
    let kek = derive_kek_argon2id(password.as_bytes(), &salt, &DEFAULT_KDF_PARAMS)?;

    // Wrap DEK
    let cipher = Aes256Gcm::new(Key::<Aes256Gcm>::from_slice(&kek));
    let aad = build_slot_aad(export_id, slot_id);
    let wrapped_dek = cipher.encrypt(
        Nonce::from_slice(&nonce),
        Payload { msg: dek, aad: &aad }
    )?;

    Ok(KeySlot {
        id: slot_id,
        slot_type: "password".to_string(),
        kdf: "argon2id".to_string(),
        kdf_params: Some(DEFAULT_KDF_PARAMS.clone()),
        salt: salt.to_vec(),
        nonce: nonce.to_vec(),
        wrapped_dek,
    })
}
