```rust
pub async fn key_rotate(
    archive_dir: &Path,
    old_password: &str,
    new_password: &str,
    keep_recovery: bool,
    progress: impl FnMut(f32),
) -> Result<RotateResult, KeyError> {
    let config_path = archive_dir.join("config.json");
    let config: Config = serde_json::from_str(&fs::read_to_string(&config_path)?)?;

    // 1. Decrypt payload with old password
    let old_dek = unwrap_dek_from_any_slot(&config, old_password)?;
    let plaintext = decrypt_all_chunks(&archive_dir, &old_dek, &config, |p| progress(p * 0.5))?;

    // 2. Generate new DEK and export_id
    let mut new_dek = [0u8; 32];
    let mut new_export_id = [0u8; 16];
    let mut new_base_nonce = [0u8; 12];
    rand::thread_rng().fill_bytes(&mut new_dek);
    rand::thread_rng().fill_bytes(&mut new_export_id);
    rand::thread_rng().fill_bytes(&mut new_base_nonce);

    // 3. Re-encrypt payload with new DEK
    let chunk_count = encrypt_all_chunks(
        &plaintext,
        &new_dek,
        &new_export_id,
        &new_base_nonce,
        config.payload.chunk_size as usize,
        &archive_dir.join("payload"),
        |p| progress(0.5 + p * 0.5),
    )?;

    // 4. Create new key slots
    let mut new_slots = vec![
        create_password_slot(new_password, &new_dek, &new_export_id, 0)?
    ];

    if keep_recovery {
        let secret = generate_recovery_secret();
        new_slots.push(create_recovery_slot(&secret, &new_dek, &new_export_id, 1)?);
        // Return secret to caller for display
    }

    // 5. Write new config
    let new_config = Config {
        version: config.version,
        export_id: base64_encode(&new_export_id),
        base_nonce: base64_encode(&new_base_nonce),
        compression: config.compression,
        kdf_defaults: config.kdf_defaults,
        payload: PayloadConfig {
            chunk_size: config.payload.chunk_size,
            chunk_count,
            files: (0..chunk_count)
                .map(|i| format!("payload/chunk-{:05}.bin", i))
                .collect(),
        },
        key_slots: new_slots,
        exported_at: Utc::now().to_rfc3339(),
        cass_version: env!("CARGO_PKG_VERSION").to_string(),
    };

    fs::write(&config_path, serde_json::to_string_pretty(&new_config)?)?;

    // 6. Regenerate integrity.json
    regenerate_integrity_manifest(&archive_dir)?;

    // 7. Zeroize old DEK
    old_dek.zeroize();
    new_dek.zeroize();

    Ok(RotateResult {
        new_dek_created_at: Utc::now(),
        slot_count: new_config.key_slots.len(),
    })
}
```

